window.METHO = {"docs": {"article": {"kind": "Article · factual report", "flag": "gb", "title": "“2,800 jobs at risk as Tata announces Port Talbot Steelworks plans”", "source": "Swansea Bay News / Tata Steel announcement", "date": "January 2024", "search": "https://www.google.com/search?q=Port+Talbot+Tata+Steel+blast+furnace+closure+jobs", "gist": "A purely factual news report: Tata Steel will shut its blast furnaces at Port Talbot, putting up to 2,800 jobs at risk, and shift to a state-subsidised “green” electric arc furnace. No opinion is offered — the stake is for the reader to uncover."}, "podcast": {"kind": "Podcast · audio analysis", "flag": "us", "title": "“The origins of ICE” — The Global Story (BBC World Service)", "source": "BBC World Service, with Camilo Montoya-Galvez (CBS News)", "date": "2026", "search": "https://www.bbc.co.uk/sounds/search?q=the%20global%20story%20ICE", "gist": "An audio episode tracing how ICE was created and why it became so controversial. The challenge: no re-reading — you must take notes, identify speakers, and follow an argument by ear."}, "video": {"kind": "Video · editorial debate", "flag": "gb", "title": "“How special is Britain and America’s relationship?” — The Economist", "source": "The Economist (Insider series)", "date": "April 2026", "search": "https://www.youtube.com/results?search_query=Economist+how+special+Britain+America+relationship", "gist": "Editors debate why the transatlantic “special relationship” is fraying, with data and expert views. The challenge: analyse an argued discourse — thesis, evidence, standpoint."}}, "modules": [{"id": "m0", "n": "00", "title": "Understand the colle", "skill": "What the exam really tests", "time": "15 min", "lead": "Before any method: what is a colle actually testing, and how does it differ from a summary or a recited lecture?", "lesson": [{"h": "What a colle evaluates", "p": "A colle tests, together: your understanding of the document, your ability to prioritise information, to reformulate, to contextualise, to build a line of reasoning, the quality of your argument, your command of English, the clarity of your delivery, your interaction with the examiner, your time management, and your ability to take previous corrections into account."}, {"h": "The ten-step arc of a colle", "p": "1) Discover the document. 2) Identify the essentials. 3) Understand the underlying issue. 4) Put it into context. 5) Formulate the key question. 6) Build an outline that answers it. 7) Select relevant examples. 8) Deliver a clear presentation. 9) Conclude. 10) Discuss and defend your ideas."}, {"h": "Four things a commentary is NOT", "p": "Not a paraphrase of the document. Not an endless summary. Not a recital of civilisation knowledge with no precise link to the document. Not an improvised opinion with no structure. A successful commentary analyses — it explains how and why, and what is at stake."}, {"h": "Understand vs summarise vs comment vs recite", "p": "Understanding = grasping the situation. Summarising = restating the essentials faithfully and briefly. Commenting = analysing the stakes, tensions and implications. Reciting = pouring out a lecture. The colle rewards the third."}], "filrouge": {"doc": "article", "steps": [{"h": "The same document, four ways", "p": "On the Port Talbot report — Understand: a steelworks is closing, jobs are at risk. Summarise: Tata will shut its blast furnaces, ~2,800 jobs at risk, shifting to a subsidised green furnace. Comment: the document stages a collision between decarbonisation and the survival of an industrial community. Recite (the trap): 'Wales has a long industrial history since the coal era…' — true, but it answers nothing."}]}, "dodont": [{"bad": "“This document speaks about a factory. First the advantages, then the disadvantages.”", "good": "“This factual report raises a sharper question: can a nation decarbonise its industry without sacrificing the communities built around it?”", "why": "The weak version summarises and announces a flat plan. The strong version already hears the tension."}], "exercises": [{"type": "qcm", "intro": "What is the examiner really looking for?", "items": [{"q": "The main goal of a colle is to…", "opts": ["Summarise the document accurately", "Analyse it and defend an argued, problematised response", "Show how much you know", "List pros and cons"], "c": 1, "fb": "A colle tests critical analysis and argument built on the document."}, {"q": "“Analysing” a document means…", "opts": ["Retelling it in your own words", "Explaining how and why it works, and what is at stake", "Translating the hard sentences", "Listing every fact"], "c": 1, "fb": "Analysis is about the how, the why and the stakes — not paraphrase."}, {"q": "Which is NOT part of what a colle evaluates?", "opts": ["Time management", "Interaction with the examiner", "Your handwriting speed", "Contextualisation"], "c": 2, "fb": "Handwriting speed is irrelevant; the rest are all assessed."}]}, {"type": "order", "intro": "Put the arc of a colle back in order.", "scrambled": ["Formulate the key question", "Discover the document", "Build an outline that answers it", "Identify the essentials", "Conclude", "Understand the underlying issue"], "correct": [1, 3, 5, 0, 2, 4], "fb": "Discover → identify essentials → understand the issue → key question → outline → conclude."}]}, {"id": "m1", "n": "01", "title": "Managing preparation time", "skill": "Time strategy", "time": "20 min", "lead": "There is no universal timing. Learn to divide whatever preparation time you are given — and to know when to move on.", "lesson": [{"h": "No universal rule", "p": "Preparation time and format vary by school and track. Your teacher's instructions always take priority. What follows is an adaptable framework, not a fixed law."}, {"h": "A workable division", "p": "Roughly: discovering + understanding the document (about a third), selecting information and contextualising (a quarter), key question + outline (a quarter), examples + introduction/conclusion + re-reading notes (the rest). Adjust to your total time."}, {"h": "The golden warning", "p": "Do not spend half of your preparation translating the first paragraph. Read for meaning, in chunks, and keep moving."}, {"h": "Knowing when to move on", "p": "Move to the next step when you can state, in one sentence, what this step gave you — the situation, the essentials, the tension, the question. If you can't after a reasonable time, note your best guess and move on; you can refine later."}], "filrouge": {"doc": "all", "steps": [{"h": "Same clock, three documents", "p": "For a written article you can re-read — budget more time for selection. For audio you cannot re-read — budget listening passes and note-taking. For video — add time to read the images. The proportions shift with the format."}]}, "dodont": [{"bad": "Spending 8 of 20 minutes translating paragraph one word by word.", "good": "Skimming the whole document first, then returning only to the passages that matter.", "why": "Translation is not comprehension. Global understanding first, detail second."}], "exercises": [{"type": "qcm", "intro": "Time-management judgement calls.", "items": [{"q": "With 20 minutes to prepare, roughly how long on discovering + understanding?", "opts": ["1–2 minutes", "About 6–8 minutes", "The full 20", "Skip it"], "c": 1, "fb": "Understanding deserves a solid share — but not all of it. Around a third is workable."}, {"q": "You're stuck on one unknown word after a minute. You should…", "opts": ["Keep decoding it until it's clear", "Infer from context and move on", "Abandon the document", "Translate the whole sentence"], "c": 1, "fb": "One unknown word rarely blocks meaning. Infer and move on."}, {"q": "The best sign it's time to move to the next step is…", "opts": ["You've used exactly the planned minutes", "You can state in one sentence what the step gave you", "You've filled a page of notes", "You feel nervous"], "c": 1, "fb": "Being able to sum up the step in a sentence shows it's done."}]}, {"type": "classify", "intro": "For a 20-minute prep, sort each task as EARLY or LATE in the preparation.", "binA": "Early", "binB": "Late", "items": [{"t": "First reading for the overall situation", "bin": "A"}, {"t": "Preparing the introduction wording", "bin": "B"}, {"t": "Identifying source, date, actors", "bin": "A"}, {"t": "Re-reading your notes before you go in", "bin": "B"}, {"t": "Building the outline", "bin": "B"}, {"t": "Grasping the general topic", "bin": "A"}]}]}, {"id": "m2", "n": "02", "title": "Reading faster and better", "skill": "Efficient reading", "time": "25 min", "lead": "Read in several passes, for meaning, without translating every word.", "lesson": [{"h": "First pass — identify the situation", "p": "Look first at: title, subtitle, source, date, author, document type, country, main people or institutions, first paragraph, last paragraph. Goal: grasp the general topic and situation."}, {"h": "Second pass — map the structure", "p": "Spot the stages, topic shifts, causes, consequences, oppositions, concessions, examples, quotations, figures, logical connectors, and repeated vocabulary. You are drawing the skeleton."}, {"h": "Third pass — select evidence", "p": "Return only to the passages you need: to verify a fact, note a precise example, grasp a nuance, prepare the commentary. Not every paragraph deserves equal attention."}, {"h": "What NOT to do", "p": "Don't translate every word, don't stop on every unknown term, don't copy whole sentences, don't read every paragraph with the same intensity, and don't confuse precision with accumulation."}, {"h": "Reading skills to train", "p": "Infer meaning from context; accept that an unknown word rarely blocks comprehension; beware false friends; read in sense-groups, not word by word; follow pronouns and references; spot the sentences that structure the text."}], "filrouge": {"doc": "article", "steps": [{"h": "First pass on Port Talbot", "p": "Title + source + date tell you: a UK steelworks, a corporate announcement, recent. First and last paragraphs frame it: closure + transition, union anger. In 60 seconds you already have the situation — no translation needed."}, {"h": "Second pass", "p": "Connectors and figures map the structure: 2,800 jobs (scale), 'green' furnace (the shift), £500m public money (the stake), 'industrial vandalism' (the opposition). Skeleton done."}]}, "dodont": [{"bad": "Translating 'blast furnace' and 'decarbonise' before reading on.", "good": "Reading the paragraph in chunks, guessing both from context, checking later only if needed.", "why": "Meaning comes from sense-groups; isolated words can wait."}], "exercises": [{"type": "qcm", "intro": "Reading strategy.", "items": [{"q": "On a first pass you should read, in priority…", "opts": ["Every paragraph in full", "Title, source, date, first and last paragraphs", "Only the figures", "The middle only"], "c": 1, "fb": "The frame (title/source/first/last) gives the situation fastest."}, {"q": "A 'false friend' is a word that…", "opts": ["Has no translation", "Looks like a French word but means something different", "Is always capitalised", "Is a proper noun"], "c": 1, "fb": "E.g. 'actually' ≠ 'actuellement'. Transparent-looking words can mislead."}, {"q": "Reading 'in sense-groups' means…", "opts": ["One word at a time", "Grouping words into meaningful chunks", "Reading aloud", "Reading only nouns"], "c": 1, "fb": "Chunking speeds reading and preserves meaning."}]}, {"type": "gap", "intro": "Fill each gap with the right reading term.", "items": [{"text": "On the first pass, I look at the title, the source and the ____ to place the document in time.", "opts": ["date", "font", "margin"], "c": 0, "fb": "The date situates the document."}, {"text": "An unknown word can often be guessed from its ____.", "opts": ["context", "spelling", "length"], "c": 0, "fb": "Context usually reveals approximate meaning."}, {"text": "Logical ____ such as 'however' or 'therefore' reveal the structure of the argument.", "opts": ["connectors", "pronouns", "adjectives"], "c": 0, "fb": "Connectors signal how ideas relate."}]}, {"type": "classify", "intro": "Sort each item: ESSENTIAL to note, or SECONDARY detail?", "binA": "Essential", "binB": "Secondary", "items": [{"t": "2,800 jobs at risk", "bin": "A"}, {"t": "The exact street address of the plant", "bin": "B"}, {"t": "The shift to a green furnace", "bin": "A"}, {"t": "The colour of the company logo", "bin": "B"}, {"t": "£500m of public money", "bin": "A"}]}]}, {"id": "m3", "n": "03", "title": "Understanding audio & video", "skill": "Listening / viewing method", "time": "30 min", "lead": "You will not catch every word — and you don't need to. Method beats panic.", "lesson": [{"h": "Before listening or watching", "p": "Use what you already have: title, source, date, image, programme name, speaker, duration, likely theme. Form a few hypotheses — but hold them loosely."}, {"h": "First listening — the big picture", "p": "Who is speaking? What is the main topic? Where and when? What is the general tone? What is the main event, claim or concern? How is it organised?"}, {"h": "Second listening — the structure", "p": "Track the different voices, topic shifts, agreements and disagreements, causes and consequences, examples, key figures, proper nouns, transitions, reformulations, interim conclusions."}, {"h": "Third listening (if allowed)", "p": "Check only what is still uncertain: figures, names, essential quotations, nuances. Don't restart from zero."}, {"h": "Taking notes by ear", "p": "Use abbreviations, arrows, symbols, spatial layout, columns per speaker, a timeline, a cause/consequence map. You are capturing structure, not a transcript."}, {"h": "Video adds pictures", "p": "Read facial expressions, images, on-screen graphics, the setting, gestures, captions, cuts, the source's visual identity — but remember images can also bias interpretation."}], "filrouge": {"doc": "podcast", "steps": [{"h": "Before pressing play (ICE podcast)", "p": "Source: BBC World Service. Guest: a CBS reporter. Title: 'The origins of ICE'. Hypothesis: history + controversy of a US immigration agency. You already expect a security-vs-liberty tension — confirm or revise it as you listen."}, {"h": "First listening", "p": "Identify: two voices (host + expert), topic (ICE's creation and its expanding powers), tone (analytical, not neutral cheerleading). That alone frames a whole commentary."}]}, "dodont": [{"bad": "Trying to write down every word the speaker says.", "good": "Capturing structure with arrows, columns and symbols, leaving gaps to fill on a second pass.", "why": "Transcribing is impossible in real time and misses the argument's shape."}], "exercises": [{"type": "qcm", "intro": "Listening / viewing method.", "items": [{"q": "On a first listening, your priority is…", "opts": ["Every exact figure", "The big picture: who, what, where, tone, structure", "Spelling every name", "A word-for-word transcript"], "c": 1, "fb": "Big picture first; details on later passes."}, {"q": "Images in a video…", "opts": ["Are always neutral", "Can support but also bias interpretation", "Should be ignored", "Replace the audio"], "c": 1, "fb": "Visuals inform — and can steer — interpretation."}, {"q": "Good audio notes rely on…", "opts": ["Full sentences", "Abbreviations, arrows and spatial layout", "One long paragraph", "Colour only"], "c": 1, "fb": "Symbols and layout capture structure fast."}]}, {"type": "order", "intro": "Put the listening method in order.", "scrambled": ["Second pass: track structure, voices, figures", "Form hypotheses from title, source, speaker", "First pass: get the big picture", "Third pass: check only what's uncertain"], "correct": [1, 2, 0, 3], "fb": "Hypotheses → big picture → structure → targeted check."}, {"type": "match", "intro": "Match each note-taking tool to its use.", "items": [{"q": "Columns", "opts": ["Separate different speakers", "Underline the title"], "c": 0, "fb": "Columns keep speakers apart."}, {"q": "A timeline", "opts": ["Order events chronologically", "List vocabulary"], "c": 0, "fb": "A timeline captures sequence."}, {"q": "Arrows", "opts": ["Show cause and consequence", "Mark spelling errors"], "c": 0, "fb": "Arrows link causes to effects."}]}]}, {"id": "m4", "n": "04", "title": "Identifying essential information", "skill": "Prioritising", "time": "20 min", "lead": "Build a mental map of the document and separate what is essential from what is merely there.", "lesson": [{"h": "The mapping questions", "p": "Who? What? Where? When? Why? How? What changed? Who is affected? What is at stake? What tension does the document reveal?"}, {"h": "Four tiers of information", "p": "Essential (without it, the document can't be understood). Supporting (explains or proves the main idea). Illustration/anecdote (makes it concrete, not always needed in a summary). Contextual (links it to a wider situation)."}, {"h": "A figure is not automatically essential", "p": "A number matters when it shows an evolution, measures a scale, reveals an inequality, contradicts a claim, or enables a comparison. Otherwise it is decoration."}, {"h": "From fifteen notes to five", "p": "Good preparation collapses a mess of notes into a handful of essential points. Ruthlessly merge and cut."}], "filrouge": {"doc": "article", "steps": [{"h": "Mapping Port Talbot", "p": "Who: Tata Steel, 2,800 workers, the union, government. What: blast-furnace closure + green furnace. Why: decarbonisation + cost. What's at stake: the survival of an industrial community vs the climate imperative. That last line is the tension."}, {"h": "Essential vs the rest", "p": "Essential: closure, jobs, green shift, public money. Supporting: union's wording. Decoration: incidental corporate details. Five points, not fifteen."}]}, "dodont": [{"bad": "Noting every figure in the document because 'numbers look important'.", "good": "Keeping only the figures that show scale, change or inequality.", "why": "A number earns its place only if it does analytical work."}], "exercises": [{"type": "classify", "intro": "Sort each element by tier: ESSENTIAL or NON-ESSENTIAL (for a summary).", "binA": "Essential", "binB": "Non-essential", "items": [{"t": "The blast furnaces will close", "bin": "A"}, {"t": "The reporter's name", "bin": "B"}, {"t": "2,800 jobs are at risk", "bin": "A"}, {"t": "An anecdote about one worker's lunch", "bin": "B"}, {"t": "The shift to a subsidised green furnace", "bin": "A"}, {"t": "The plant's founding date, mentioned in passing", "bin": "B"}]}, {"type": "qcm", "intro": "Prioritising judgement.", "items": [{"q": "A statistic becomes essential when it…", "opts": ["Is a big number", "Shows change, scale, inequality or contradiction", "Appears first", "Is a percentage"], "c": 1, "fb": "Function, not size, makes a figure essential."}, {"q": "An anecdote in a document is…", "opts": ["Always essential", "Often an illustration, not always needed in a summary", "Never useful", "The main idea"], "c": 1, "fb": "Anecdotes illustrate; they rarely belong in a tight summary."}, {"q": "'What is at stake?' helps you find…", "opts": ["The word count", "The underlying issue / tension", "The author's age", "The font"], "c": 1, "fb": "It points straight at the tension."}]}]}, {"id": "m5", "n": "05", "title": "Writing an effective summary", "skill": "Summarising", "time": "25 min", "lead": "Faithful, neutral, concise, structured, reformulated — understandable by someone who never saw the document.", "lesson": [{"h": "What a good summary is", "p": "Faithful, neutral, concise, structured, reformulated, prioritised, and clear to someone who hasn't seen the document."}, {"h": "What it is NOT", "p": "Not a paragraph-by-paragraph crawl, not the document's own wording, not a pile of every figure, not a personal opinion, not the start of your commentary, not a list of details standing in for understanding."}, {"h": "Three steps: reduce, regroup, reformulate", "p": "Reduce: cut secondary details, repetitions, non-essential illustrations. Regroup: gather information that serves the same function. Reformulate: restate in clear, precise words of your own."}], "filrouge": {"doc": "article", "steps": [{"h": "A model summary of Port Talbot", "p": "'A major steelmaker has announced it will close its blast furnaces, putting thousands of jobs at risk, and switch to a lower-carbon furnace supported by public funds; unions have condemned the decision as needlessly destructive.' Faithful, neutral, reformulated, one sentence."}]}, "dodont": [{"bad": "'The first paragraph says… then the second paragraph says… then the third…'", "good": "One reworded, prioritised sentence capturing closure + jobs + green shift + reaction.", "why": "A summary follows meaning, not the document's paragraph order."}, {"bad": "'This shocking, scandalous closure…'", "good": "'The company will close the furnaces…' (neutral).", "why": "A summary carries no opinion."}], "exercises": [{"type": "qcm", "intro": "Summary quality control.", "items": [{"q": "A good summary is…", "opts": ["Paragraph-by-paragraph", "Faithful, neutral, concise and reformulated", "Full of quotations", "Your opinion of the text"], "c": 1, "fb": "Faithful, neutral, concise, reworded."}, {"q": "Which sentence belongs in a summary?", "opts": ["'This outrageous decision proves capitalism has failed.'", "'The company will close its furnaces, cutting thousands of jobs.'", "'I think the workers are right.'", "'Firstly, the second paragraph explains…'"], "c": 1, "fb": "Neutral, faithful, reworded — no opinion, no paragraph crawl."}, {"q": "The three summary steps are…", "opts": ["Read, translate, copy", "Reduce, regroup, reformulate", "Quote, list, conclude", "Skim, skip, stop"], "c": 1, "fb": "Reduce → regroup → reformulate."}]}, {"type": "spot", "intro": "Spot the flaw in each attempted summary.", "items": [{"q": "'The document is about a factory and many other important things.'", "opts": ["Too precise", "Too vague — says nothing concrete", "Too neutral", "Perfect"], "c": 1, "fb": "Vague filler; name the actual content."}, {"q": "'This disgraceful closure shows how greedy the company is.'", "opts": ["Too long", "Injects opinion — not neutral", "Too short", "Well judged"], "c": 1, "fb": "A summary stays neutral."}, {"q": "'Paragraph one says X, paragraph two says Y, paragraph three says Z.'", "opts": ["Follows the text mechanically instead of prioritising", "Too reworded", "Too concise", "Ideal structure"], "c": 0, "fb": "Follow meaning, not paragraph order."}]}, {"type": "order", "intro": "Put the three summary steps in order.", "scrambled": ["Reformulate in your own clear words", "Reduce: cut secondary details", "Regroup information with the same function"], "correct": [1, 2, 0], "fb": "Reduce → regroup → reformulate."}]}, {"id": "m6", "n": "06", "title": "Contextualising the document", "skill": "Context", "time": "30 min", "lead": "The priority skill of the introduction. Title + date + source is NOT context.", "lesson": [{"h": "What contextualising really means", "p": "Explaining what is needed to understand: why this document appeared now, what event or debate triggered it, the political/economic/social/cultural backdrop, the institutions and populations involved, how it connects to the civilisation syllabus, and why it matters."}, {"h": "Four things to avoid", "p": "Decorative knowledge (true but useless here). Historical dumping (a long chronology that delays analysis). Unsupported claims (vague, exaggerated, unverifiable). And the bare minimum (title/date/source only)."}, {"h": "A five-step method", "p": "1) Identify the immediate event. 2) Identify the broader debate. 3) Select one or two pieces of civilisation knowledge. 4) Explain the connection. 5) Stop before context overwhelms the document."}], "filrouge": {"doc": "article", "steps": [{"h": "Contextualising Port Talbot well", "p": "Immediate event: Tata's closure announcement. Broader debate: the UK's industrial decarbonisation and 'just transition'. Civilisation knowledge: post-industrial decline in Wales; Britain's net-zero commitments. Connection: this single plant crystallises a national dilemma. Then stop — don't recite the whole history of British coal."}]}, "dodont": [{"bad": "'Since the Industrial Revolution, Britain has had many factories and much history…'", "good": "'This closure lands amid Britain's push for net zero, turning one plant into a test of whether decarbonisation can spare industrial communities.'", "why": "The first is historical dumping; the second links a precise event to a live debate."}], "exercises": [{"type": "qcm", "intro": "Context: relevant or not?", "items": [{"q": "Good contextualisation…", "opts": ["Lists the country's entire history", "Explains why THIS document matters now", "Gives only title and date", "Avoids the syllabus"], "c": 1, "fb": "Relevant context explains the document's immediate significance."}, {"q": "'Historical dumping' means…", "opts": ["A precise, useful fact", "A long chronology that delays analysis", "A single date", "A quotation"], "c": 1, "fb": "Too much history, too little analysis."}, {"q": "After the immediate event, the next step is to identify…", "opts": ["The broader debate", "The word count", "The author's salary", "The font size"], "c": 0, "fb": "Move from the event to the wider debate."}]}, {"type": "classify", "intro": "For the Port Talbot document, sort each fact: RELEVANT context or OFF-TOPIC?", "binA": "Relevant", "binB": "Off-topic", "items": [{"t": "Britain's net-zero commitments", "bin": "A"}, {"t": "The date the Eiffel Tower was built", "bin": "B"}, {"t": "Post-industrial decline in Wales", "bin": "A"}, {"t": "The CEO's favourite football team", "bin": "B"}, {"t": "The 'just transition' debate", "bin": "A"}]}, {"type": "order", "intro": "Put the five-step contextualisation method in order.", "scrambled": ["Explain the connection to the document", "Identify the immediate event", "Stop before context overwhelms the document", "Identify the broader debate", "Select one or two civilisation facts"], "correct": [1, 3, 4, 0, 2], "fb": "Event → debate → select facts → connect → stop."}]}, {"id": "m7", "n": "07", "title": "Finding the key question", "skill": "Problematising", "time": "30 min", "lead": "The problematique is the key question your presentation will answer — and it must reveal a tension. Never 'To what extent'.", "lesson": [{"h": "A key question = a tension", "p": "A strong problematic reveals a tension, a contradiction, a transformation, a paradox, a gap between an ideal and a reality, a conflict of priorities, or a wider stake exposed by the document."}, {"h": "It must be / it must not be", "p": "Must be: clear, precise, genuinely interrogative, tied to the document, broad enough to think with, focused enough to answer, a single main question. Must NOT be: a restated title, a factual or yes/no question, an endless or double question, a generic all-purpose formula, empty abstraction, or disconnected from the document."}, {"h": "Four steps", "p": "1) Identify the topic. 2) Identify the tension (what resists a simple explanation). 3) Identify the broader stakes (why the tension matters). 4) Turn it into one key question that analyses both the document and its stakes."}, {"h": "Flexible openers (not recipes)", "p": "How does this event reveal…? Why has… become…? How is… reshaping…? What does this controversy reveal about…? Why does… remain difficult despite…? What does the gap between… and… reveal about…? — never 'To what extent'."}], "filrouge": {"doc": "all", "steps": [{"h": "Article — Port Talbot", "p": "Tension: progress vs its human cost. → 'Can a nation decarbonise heavy industry without sacrificing the communities built around it?'"}, {"h": "Podcast — ICE", "p": "Tension: security vs liberty. → 'How far can a democracy expand enforcement powers before undermining the freedoms it claims to protect?'"}, {"h": "Video — special relationship", "p": "Tension: loyalty vs interest. → 'Is the transatlantic bond still a partnership of values, or now merely one of convenience?'"}]}, "dodont": [{"bad": "'To what extent is ICE controversial?'", "good": "'How far can a state expand enforcement before it erodes the liberties it claims to defend?'", "why": "'To what extent' is banned here; the strong version names a real tension."}, {"bad": "'What is a steelworks?' (factual)", "good": "'Can decarbonisation spare the communities it disrupts?' (tension).", "why": "A factual question isn't a problematic."}], "exercises": [{"type": "qcm", "intro": "Spot the real problematic.", "items": [{"q": "Which is a genuine key question?", "opts": ["'What is ICE?'", "'How far can enforcement grow before it erodes liberty?'", "'Is immigration good or bad?'", "'To what extent is ICE special?'"], "c": 1, "fb": "It names a tension and can be argued — unlike a factual or yes/no question."}, {"q": "A key question must NOT be…", "opts": ["Tied to the document", "A single main question", "A restated title", "Genuinely interrogative"], "c": 2, "fb": "Restating the title is not problematising."}, {"q": "The forbidden opener on this site is…", "opts": ["'How does… reveal…?'", "'To what extent…?'", "'Why has… become…?'", "'What does the gap between… reveal?'"], "c": 1, "fb": "'To what extent' is banned; use a sharper opener."}]}, {"type": "order", "intro": "Rebuild the path to a key question.", "scrambled": ["Turn it into one key question", "Identify the topic", "Identify the broader stakes", "Identify the tension"], "correct": [1, 3, 2, 0], "fb": "Topic → tension → stakes → question."}, {"type": "spot", "intro": "Why is each weak question weak?", "items": [{"q": "'Is the monarchy good or bad?'", "opts": ["Too precise", "A crude yes/no with no tension", "Too tied to the document", "Perfect"], "c": 1, "fb": "Yes/no value questions flatten the tension."}, {"q": "'What does this document talk about and is it important and what happens next?'", "opts": ["A triple question", "Too focused", "Too interrogative", "Ideal"], "c": 0, "fb": "One main question only — not three."}, {"q": "'To what extent is the special relationship special?'", "opts": ["Uses a banned opener and echoes the title", "Too specific", "Names a clear tension", "Well built"], "c": 0, "fb": "Banned opener + restated title."}]}]}, {"id": "m8", "n": "08", "title": "Building a relevant outline", "skill": "Outlining", "time": "30 min", "lead": "Never advantages/disadvantages. A plan is a progressive answer to your key question.", "lesson": [{"h": "The banned plan", "p": "No advantages/disadvantages, pros/cons, for/against, yes/no, positive/negative. Splitting the topic into two camps is not a line of reasoning."}, {"h": "What each part must do", "p": "Defend an idea, advance one step of the answer, stay distinct from the others, carry examples, move the reasoning forward, and stay tied to the document and context."}, {"h": "Document structure ≠ presentation outline", "p": "The order the journalist chose is not necessarily the order you choose to answer your own key question. Reorganise around your argument, not theirs."}, {"h": "Possible logics (not universal recipes)", "p": "Visible event → underlying causes → broader consequences. Official narrative → contradictions → implications. Immediate situation → structural factors → possible developments. Ideal/promise → implementation → limits/redefinition. Local case → national pattern → wider significance. Diagnosis → mechanisms → consequences. Apparent success → hidden weaknesses → long-term challenges. Historical legacy → current transformation → future stakes."}], "filrouge": {"doc": "article", "steps": [{"h": "An outline that moves (Port Talbot)", "p": "Key question: can decarbonisation spare industrial communities? I — the green imperative is genuine (necessity, climate goals, the new furnace). II — but its human cost is borne unequally (2,800 jobs, a community, 'managed decline'). III — so the real issue is HOW transition is governed (retraining, phasing, the £500m). Thesis → complication → reframing."}]}, "dodont": [{"bad": "I — Advantages of the closure. II — Disadvantages.", "good": "I — the green case is real. II — its cost is unequal. III — the true issue is how transition is governed.", "why": "A catalogue doesn't move; a real plan progresses."}], "exercises": [{"type": "qcm", "intro": "Outline test.", "items": [{"q": "A relevant outline…", "opts": ["Splits the topic into pros and cons", "Progressively answers the key question", "Copies the document's order", "Lists everything you know"], "c": 1, "fb": "It answers the question step by step."}, {"q": "If the headings could be swapped without changing anything, the plan…", "opts": ["Is perfectly balanced", "Probably lacks progression", "Is too detailed", "Is ideal"], "c": 1, "fb": "Interchangeable parts = no real movement."}, {"q": "The document's structure and your outline…", "opts": ["Must always match", "Can differ — you organise around your question", "Are irrelevant", "Must be reversed"], "c": 1, "fb": "Reorganise around your argument, not the author's."}]}, {"type": "order", "intro": "Arrange into a plan that moves (thesis → complication → reframing).", "scrambled": ["The cost falls unequally on one community", "A just transition reframes the whole debate", "Decarbonising steel is a genuine necessity"], "correct": [2, 0, 1], "fb": "Take the case seriously → complicate → transcend."}, {"type": "spot", "intro": "Diagnose each outline.", "items": [{"q": "I — Good sides of ICE. II — Bad sides of ICE.", "opts": ["A hidden pros/cons plan", "A progressive plan", "A causal plan", "Ideal"], "c": 0, "fb": "Good/bad = pros and cons in disguise."}, {"q": "I — What the report says. II — What the report says next. III — The end of the report.", "opts": ["Follows the document instead of an argument", "A strong thesis plan", "Well problematised", "Perfect"], "c": 0, "fb": "It mirrors the text, it doesn't argue."}, {"q": "I — The promise of a green transition. II — Its uneven implementation. III — How it could be governed justly.", "opts": ["A genuine progressive plan", "A pros/cons plan", "Off-topic", "A summary"], "c": 0, "fb": "Promise → implementation → redefinition: it moves."}]}]}, {"id": "m9", "n": "09", "title": "Finding & using examples", "skill": "Evidence", "time": "25 min", "lead": "A name dropped is not an example. Precise, exact, explained, tied to the argument.", "lesson": [{"h": "Where examples come from", "p": "The document itself, the English course, civilisation classes, recent news, a comparable situation, a relevant historical event, an institution, a policy decision, a verified statistic, a speech or public policy."}, {"h": "What an example must be", "p": "Precise, exact, understandable, directly tied to the argument, explained, and used to prove or qualify something. An isolated proper noun is not an example. A recited date is not an argument. An invented statistic must never be used."}, {"h": "The four-move structure", "p": "Make the point. Give precise evidence. Explain what it demonstrates. Link it back to the key question."}, {"h": "If you can't think of an example", "p": "Return to the document's own facts; use a well-known institution; compare with a recent case seen in class; rescale the argument more cautiously; acknowledge the limits of your knowledge rather than invent."}], "filrouge": {"doc": "article", "steps": [{"h": "A worked example", "p": "Point: transition costs fall unevenly. Evidence: Port Talbot's 2,800 jobs concentrated in one town. Explanation: a national policy becomes a local shock. Link: which is why the key question is not green vs jobs, but how transition is governed."}]}, "dodont": [{"bad": "'Thatcher. Deindustrialisation. Wales.' (name-dropping)", "good": "'The 1980s pit closures show how quickly a mono-industry town can collapse when its core employer goes — the risk Port Talbot now faces.'", "why": "Names must be explained and tied to the argument."}], "exercises": [{"type": "qcm", "intro": "Evidence quality.", "items": [{"q": "An example must above all be…", "opts": ["Impressive-sounding", "Precise, exact and tied to the argument", "Recent", "Foreign"], "c": 1, "fb": "Relevance and precision beat name-dropping."}, {"q": "An isolated proper noun is…", "opts": ["A strong example", "Not an example — it needs explanation and a link", "The best evidence", "A conclusion"], "c": 1, "fb": "Explain it and connect it, or it proves nothing."}, {"q": "If you can't find an example, you should…", "opts": ["Invent a plausible statistic", "Return to the document's facts or a known case", "Skip the argument", "Guess a number"], "c": 1, "fb": "Never invent — fall back on the document or a known case."}]}, {"type": "order", "intro": "Put the four-move example structure in order.", "scrambled": ["Link it back to the key question", "Make the point", "Explain what it demonstrates", "Give precise evidence"], "correct": [1, 3, 2, 0], "fb": "Point → evidence → explanation → link."}, {"type": "match", "intro": "Match each item to its verdict.", "items": [{"q": "'Unemployment rose sharply after the plant shut, straining local services.'", "opts": ["Usable evidence (explained)", "Name-dropping"], "c": 0, "fb": "Explained and tied to the point."}, {"q": "'Reagan. Deregulation.'", "opts": ["Name-dropping", "Usable evidence"], "c": 0, "fb": "Bare names prove nothing."}, {"q": "'The document's own £500m figure shows the state's stake.'", "opts": ["Evidence from the document", "An invented statistic"], "c": 0, "fb": "Drawn straight from the text."}]}]}, {"id": "m10", "n": "10", "title": "Building the introduction", "skill": "Introductions", "time": "25 min", "lead": "A coherent construction, not a list of memorised sentences. Context is valued above all.", "lesson": [{"h": "What it may contain", "p": "A directly relevant hook, a precise presentation of the document, contextualisation, the identification of the central issue, the key question, and the announcement of the plan — following your teacher's expectations."}, {"h": "The hook: what to avoid", "p": "No memorised quotation with no precise link, no dictionary definition, no 'Since the dawn of time', no sweeping generality about society/mankind/the world, no spectacular claim you can't justify."}, {"h": "Useful, flexible openers", "p": "'This document was published in the immediate aftermath of…' · 'It comes at a time when…' · 'The report focuses on…, but it also raises the broader issue of…' · 'This local event reflects a wider debate over…' · 'Beyond the immediate controversy, the document reveals…' · 'The key question is therefore…' — never 'To what extent'."}], "filrouge": {"doc": "article", "steps": [{"h": "An annotated model introduction", "p": "[Hook] 'In Port Talbot, saving the planet and saving a town have been set against each other.' [Document] 'This factual report announces Tata's blast-furnace closure and its shift to a subsidised green furnace.' [Context] 'It lands amid Britain's net-zero push.' [Tension] 'It stages a collision between climate action and industrial communities.' [Key question] 'Can decarbonisation spare the communities it disrupts?' [Plan] 'I will first…, then…, before…'"}]}, "dodont": [{"bad": "'Since the dawn of time, work has mattered to mankind.'", "good": "'In Port Talbot, saving the planet and saving a town have been set against each other.'", "why": "Specific and document-tied beats timeless and empty."}], "exercises": [{"type": "order", "intro": "Put the moves of an introduction in order.", "scrambled": ["State the key question", "A relevant hook", "Announce the plan", "Present the document", "Contextualise / name the tension"], "correct": [1, 3, 4, 0, 2], "fb": "Hook → document → context/tension → key question → plan."}, {"type": "spot", "intro": "Find the flaw in each introduction move.", "items": [{"q": "'Since the beginning of humanity, immigration has always existed.'", "opts": ["A sweeping, empty generality", "Too precise", "Well contextualised", "Ideal hook"], "c": 0, "fb": "Avoid 'since the dawn of time' openers."}, {"q": "An intro with hook, document, context, key question — then it stops.", "opts": ["It omits the plan announcement", "It's complete", "It over-explains", "It lacks a hook"], "c": 0, "fb": "Announce the plan so the jury can follow."}, {"q": "'To what extent is this issue important?'", "opts": ["Uses a banned opener", "A strong key question", "Perfectly focused", "Well tied to the document"], "c": 0, "fb": "'To what extent' is banned here."}]}, {"type": "match", "intro": "Match each sentence to its function in the introduction.", "items": [{"q": "'It comes at a time when Britain is pursuing net zero.'", "opts": ["Context", "Plan announcement"], "c": 0, "fb": "That's contextualisation."}, {"q": "'I will first…, then…, before…'", "opts": ["Plan announcement", "Hook"], "c": 0, "fb": "That's the plan announcement."}, {"q": "'Can decarbonisation spare the communities it disrupts?'", "opts": ["Key question", "Document presentation"], "c": 0, "fb": "That's the key question."}]}]}, {"id": "m11", "n": "11", "title": "Developing the commentary", "skill": "Argumentation", "time": "30 min", "lead": "Each part is a reasoning, not a list. The document must not vanish after the introduction.", "lesson": [{"h": "A flexible part structure", "p": "State the main idea; explain it; connect it to the document; add relevant evidence or context; analyse the significance; link back to the key question; transition to the next idea."}, {"h": "The balance to hold", "p": "Reference to the document, outside knowledge, analysis, examples, nuance — in proportion. The document must not disappear; the course must not crush it; personal opinion must not replace analysis."}, {"h": "Formulations serve thought, not recital", "p": "Use function-based phrases (introduce an argument, explain, give evidence, refer to the document, put into perspective, contrast, concede, qualify, draw a consequence, return to the key question, move on) — to structure thinking, never to pad."}], "filrouge": {"doc": "article", "steps": [{"h": "One developed part", "p": "Idea: the transition's cost is unequal. Explain: national policy, local shock. Document: the report's 2,800 jobs in one town. Analysis: a community, not just a workforce, is exposed. Link: which is why 'how' matters more than 'whether'. Transition: 'This raises the deeper question of governance…'"}]}, "dodont": [{"bad": "A part that lists five facts from the document with no analysis.", "good": "A part built on one idea, evidenced, analysed, and linked back to the question.", "why": "A list informs; a paragraph argues."}], "exercises": [{"type": "order", "intro": "Order the moves within a commentary part.", "scrambled": ["Link back to the key question", "State the main idea", "Add evidence or context", "Explain it", "Analyse the significance"], "correct": [1, 3, 2, 4, 0], "fb": "Idea → explain → evidence → analysis → link back."}, {"type": "match", "intro": "Match each phrase to its function.", "items": [{"q": "'This is precisely what the document illustrates when…'", "opts": ["Referring to the document", "Concluding"], "c": 0, "fb": "It refers back to the text."}, {"q": "'Admittedly…, yet…'", "opts": ["Conceding then qualifying", "Giving evidence"], "c": 0, "fb": "A concession followed by a qualification."}, {"q": "'This leads us back to our central question…'", "opts": ["Returning to the key question", "Introducing a hook"], "c": 0, "fb": "It returns to the problematic."}]}, {"type": "qcm", "intro": "Argumentation judgement.", "items": [{"q": "After the introduction, the document should…", "opts": ["Disappear — now it's all context", "Stay present throughout the commentary", "Appear only in the conclusion", "Be quoted in full"], "c": 1, "fb": "Keep returning to the document."}, {"q": "A commentary part should be built on…", "opts": ["A list of facts", "One governing idea, evidenced and analysed", "Your personal opinion", "A quotation chain"], "c": 1, "fb": "One idea, argued — not a list."}, {"q": "Ready-made phrases should…", "opts": ["Replace your thinking", "Serve and structure your thinking", "Fill time", "Be recited in order"], "c": 1, "fb": "They serve thought, never replace it."}]}]}, {"id": "m12", "n": "12", "title": "Concluding & finding an opening", "skill": "Conclusions", "time": "20 min", "lead": "Answer the key question explicitly, then open onto a wider horizon — never a bare summary.", "lesson": [{"h": "What a conclusion must do", "p": "Answer the key question clearly, synthesise the reasoning (without repeating the plan word for word), show what the analysis revealed, and offer a relevant opening."}, {"h": "Conclusions to avoid", "p": "'This issue is very complicated.' 'There are advantages and disadvantages.' 'Only time will tell.' 'Everyone has a different opinion.' 'We'll have to wait and see.' 'This will remain important in the future.' All empty."}, {"h": "A good opening", "p": "Extends the analysis precisely, stays tied to the stake, feels logical (not a giant new topic), and introduces a comparison, an evolution, or a neighbouring question. Types: comparison with another country, recent evolution, longer-term consequence, institutional question, generational shift, unresolved contradiction, another case revealing the same tension."}], "filrouge": {"doc": "article", "steps": [{"h": "A model conclusion + opening", "p": "Answer: decarbonisation and community survival are not opposites — but only if transition is governed justly. Opening: 'Port Talbot may be less a Welsh story than a rehearsal for every industrial democracy facing the same reckoning.'"}]}, "dodont": [{"bad": "'In conclusion, there are pros and cons and only time will tell.'", "good": "'Decarbonisation need not doom communities — provided transition is governed justly; Port Talbot rehearses a reckoning every industrial democracy will face.'", "why": "Answer the question and open outward; don't sit on the fence."}], "exercises": [{"type": "qcm", "intro": "Conclusion quality.", "items": [{"q": "A conclusion must first…", "opts": ["Repeat the plan word for word", "Answer the key question explicitly", "Introduce a brand-new topic", "Summarise every paragraph"], "c": 1, "fb": "Answer the question you raised."}, {"q": "Which is an empty conclusion?", "opts": ["'Decarbonisation need not doom communities if transition is just.'", "'Only time will tell.'", "'The gap reveals a governance failure.'", "'This rehearses a wider reckoning.'"], "c": 1, "fb": "'Only time will tell' says nothing."}, {"q": "A good opening…", "opts": ["Launches a huge new subject", "Extends the analysis to a neighbouring question", "Repeats the introduction", "Lists sources"], "c": 1, "fb": "It extends, it doesn't restart."}]}, {"type": "spot", "intro": "Diagnose each conclusion.", "items": [{"q": "'In conclusion, the monarchy has good and bad sides.'", "opts": ["Sits on the fence, no answer", "Answers precisely", "Opens well", "Ideal"], "c": 0, "fb": "It takes no position."}, {"q": "'To conclude, this proves capitalism is evil.'", "opts": ["Overreach beyond the evidence", "A measured answer", "A good opening", "Neutral"], "c": 0, "fb": "An unsupported, sweeping claim."}, {"q": "'Decarbonisation and communities can coexist if transition is governed justly — a test now facing every industrial democracy.'", "opts": ["Clear answer + opening", "Empty", "A summary", "Off-topic"], "c": 0, "fb": "Answers, then opens outward."}]}]}, {"id": "m13", "n": "13", "title": "Speaking clearly & using notes", "skill": "Oral delivery", "time": "25 min", "lead": "A good oral is not a text read aloud. Delivery is a skill you can train.", "lesson": [{"h": "What to work on", "p": "Pace, pauses, articulation, intonation, stress, volume, sense-groups, transitions, eye contact, posture, note handling, correcting an error, recovering after a blank."}, {"h": "Notes are a map, not a script", "p": "Turn full sentences into keywords, arrows, abbreviations, examples, transitions, key dates, pronunciation reminders. You should be able to speak from a glance, not read."}, {"h": "Phrases to handle a difficulty", "p": "'Let me rephrase that.' · 'What I mean is…' · 'I should qualify that point.' · 'A more accurate way of putting it would be…' · 'Let me start again.' · 'The main point is…' · 'I can't recall the exact figure, but the broader trend is…' — and never invent a forgotten figure."}], "filrouge": {"doc": "all", "link": true, "steps": [{"h": "Train it in the Colle Trainer", "p": "The Colle Trainer draws a real document of the day, walks you through analysis, question and plan, then times your spoken performance — with a full transition bank. That is where delivery is built."}]}, "dodont": [{"bad": "Reading every word, eyes down, flat tone, no transitions.", "good": "Glancing at keyword notes, eyes up, signposting each move, slowing on the key question.", "why": "The jury grades an oral performance, not a recited text."}], "exercises": [{"type": "qcm", "intro": "Oral delivery.", "items": [{"q": "Good notes for speaking are…", "opts": ["Full written sentences", "Keywords, arrows and abbreviations", "A verbatim script", "Blank"], "c": 1, "fb": "Keywords let you speak, not read."}, {"q": "If you forget a figure, you should…", "opts": ["Invent a plausible one", "Give the broader trend honestly", "Stop talking", "Guess confidently"], "c": 1, "fb": "Never invent — give the trend."}, {"q": "To recover after a blank, a good phrase is…", "opts": ["'Let me rephrase that / the main point is…'", "Silence until it returns", "'I don't know'", "Change the subject entirely"], "c": 0, "fb": "A recovery phrase keeps you in control."}]}, {"type": "gap", "intro": "Complete each self-correction phrase.", "items": [{"text": "A more ____ way of putting it would be…", "opts": ["accurate", "loud", "final"], "c": 0, "fb": "'A more accurate way of putting it…'"}, {"text": "I can't recall the exact figure, but the broader ____ is clear.", "opts": ["trend", "font", "colour"], "c": 0, "fb": "Give the trend, not an invented number."}, {"text": "Let me ____ that point.", "opts": ["qualify", "ignore", "shout"], "c": 0, "fb": "'Let me qualify that point.'"}]}]}, {"id": "m14", "n": "14", "title": "Handling the discussion", "skill": "Interaction", "time": "25 min", "lead": "The examiner's questions test your poise and nuance — listen fully, answer directly, defend respectfully.", "lesson": [{"h": "How to handle a question", "p": "Listen to the end; identify what is really asked; answer directly; justify; give an example; qualify; return to the document; acknowledge a limit; ask for clarification if needed; correct an over-strong claim; disagree respectfully."}, {"h": "Useful formulations", "p": "'If I understand your question correctly…' · 'I would argue that…' · 'The document suggests that…, although…' · 'One example that supports this is…' · 'I would distinguish between…' · 'I agree up to a point, but…' · 'I'm not certain of the exact figure, so I'll focus on…' · 'Could you clarify what you mean by…?' · 'I hadn't considered that, but…' · 'That is an important limitation to my argument.'"}, {"h": "What not to do", "p": "Don't answer before thinking; don't recite a chunk of your commentary; don't dodge the question; don't pretend to know something you don't; don't answer only yes or no; don't become aggressive when you disagree; don't repeat the same idea."}], "filrouge": {"doc": "all", "steps": [{"h": "A weak answer vs a strong one", "p": "Q: 'Isn't closing the plant simply necessary?' Weak: 'Yes.' Strong: 'It may be necessary for decarbonisation, although the document shows the cost falls on one community — which is why the real issue is how the transition is handled.'"}]}, "dodont": [{"bad": "Answering 'yes' and stopping, or reciting part of your commentary.", "good": "A direct answer, justified, qualified, tied back to the document.", "why": "Interaction rewards nuance and engagement, not recitation."}], "exercises": [{"type": "qcm", "intro": "Discussion strategy.", "items": [{"q": "When you disagree with the examiner, you should…", "opts": ["Become firm and defensive", "Disagree respectfully and give a reason", "Immediately concede everything", "Repeat your point louder"], "c": 1, "fb": "Respectful, reasoned disagreement is valued."}, {"q": "If you don't understand a question, you should…", "opts": ["Guess and hope", "Ask for clarification politely", "Stay silent", "Answer a different question"], "c": 1, "fb": "'Could you clarify what you mean by…?'"}, {"q": "If a question exposes an error in your presentation, you should…", "opts": ["Deny it", "Acknowledge the limitation and adjust", "Change the subject", "Repeat the error"], "c": 1, "fb": "Owning a limit shows maturity."}]}, {"type": "match", "intro": "Match each examiner move to your best response type.", "items": [{"q": "A request for clarification of your idea", "opts": ["Restate it more precisely with an example", "Recite your whole part again"], "c": 0, "fb": "Clarify precisely, with evidence."}, {"q": "A counter-example you hadn't considered", "opts": ["'I hadn't considered that, but…' then integrate it", "Insist you were right"], "c": 0, "fb": "Acknowledge, then respond."}, {"q": "A yes/no-looking question", "opts": ["Answer, then justify and qualify", "Just say yes or no"], "c": 0, "fb": "Never leave it at yes/no."}]}]}, {"id": "m15", "n": "15", "title": "Full colle simulator", "skill": "Putting it all together", "time": "open", "lead": "Mobilise every skill on a real document of the day, step by step, with a calm timer.", "lesson": [{"h": "How the simulator works", "p": "Choose a country and a document, set your preparation and speaking times, then move through the full arc: discover, take notes, select essentials, add context, find the tension, write the key question, build the outline, choose examples, prepare intro and conclusion, then speak and self-assess against a criteria grid."}, {"h": "An honest tool", "p": "The simulator structures and times your work and saves your notes locally. It does not grade the content of open production automatically — no static page can. Compare your work against the criteria grid, and above all bring it to a real colle for a teacher's feedback."}], "filrouge": {"doc": "all", "sim": true, "steps": [{"h": "Your document", "p": "The simulator pulls a genuine article of the day so you practise on fresh material every time — exactly like a real colle."}]}, "dodont": [{"bad": "Rushing straight to speaking with no notes or key question.", "good": "Following the arc: essentials → context → tension → question → outline → examples → intro/conclusion → speak.", "why": "The method is what the simulator is training."}], "exercises": []}], "closing": {"title": "The real training ground is the classroom", "p1": "This page is a method and a warm-up — not a substitute. The best place to learn how to problematise, think and speak in English is the English lesson itself, with a teacher's feedback, live debate, and the chance to use your voice in front of others.", "p2": "Preparing your colles properly is essential. Work through these steps yourself, do your own research, and build your own reflexes — rather than leaning on ChatGPT for every answer. Train your mind; don't outsource it."}, "diagnostic": {"intro": "Quick self-check: tick every statement that sounds like you. It isn't a scientific test — it simply points you to the modules worth starting with.", "items": [{"t": "I understand the document but don't know what to keep.", "mods": ["m4"]}, {"t": "I spend too long translating.", "mods": ["m2", "m1"]}, {"t": "I can't follow an audio document.", "mods": ["m3"]}, {"t": "My summary is too long.", "mods": ["m5"]}, {"t": "My key question is too general.", "mods": ["m7"]}, {"t": "I often build a pros-and-cons plan.", "mods": ["m8"]}, {"t": "I lack examples.", "mods": ["m9"]}, {"t": "My introduction lacks context.", "mods": ["m6", "m10"]}, {"t": "I read my notes too much.", "mods": ["m13"]}, {"t": "I panic during the questions.", "mods": ["m14"]}, {"t": "I run over time.", "mods": ["m1"]}, {"t": "I don't know how to conclude.", "mods": ["m12"]}]}, "tools": {"context_builder": {"title": "The Context Builder", "intro": "Fill in each field to assemble a solid contextualisation. This gives you a structure to complete — not a ready-made introduction. The real wording, and its judgement, are yours.", "fields": [{"k": "country", "label": "Country / region", "ph": "e.g. Wales, United Kingdom"}, {"k": "actor", "label": "Institution or group", "ph": "e.g. Tata Steel, the union, the government"}, {"k": "event", "label": "Immediate event", "ph": "e.g. the announced closure of the blast furnaces"}, {"k": "issue", "label": "Broader issue", "ph": "e.g. industrial decarbonisation / just transition"}, {"k": "fact", "label": "One useful civilisation fact", "ph": "e.g. post-industrial decline in Wales"}, {"k": "link", "label": "Connection with the document", "ph": "e.g. this plant crystallises a national dilemma"}], "template": "This document concerns {actor} in {country}. It was published against the backdrop of {event}, which belongs to the wider debate on {issue}. Knowing that {fact}, we can see why {link}."}, "key_question_workshop": {"title": "The Key Question Workshop", "intro": "A guided, step-by-step path to your own key question. It never generates the problematic for you — it makes you build it. 'To what extent' is not accepted.", "steps": [{"k": "topic", "label": "Step 1 — The topic", "ph": "What is the document concretely about?"}, {"k": "tension", "label": "Step 2 — The tension", "ph": "What resists a simple explanation? (e.g. progress vs its human cost)"}, {"k": "stakes", "label": "Step 3 — The broader stakes", "ph": "Why does this tension matter beyond the document?"}, {"k": "question", "label": "Step 4 — Your key question", "ph": "Turn it into ONE real question (not 'To what extent…')"}], "tensions": ["Criticism vs Justification", "Progress vs Danger", "Individual vs Society", "Freedom vs Control", "Tradition vs Change", "Equality vs Merit", "Global vs National", "Rights vs Responsibilities"], "openers": ["How does… reveal…?", "Why has… become…?", "How is… reshaping…?", "What does this controversy reveal about…?", "Why does… remain difficult despite…?", "What does the gap between… and… reveal about…?"]}, "simulator": {"title": "Full colle simulator", "intro": "Practise the whole arc on a real document of the day. Your notes are saved locally in this browser only.", "steps": [{"k": "notes", "label": "1 — Discover & take notes", "ph": "First-pass notes: situation, source, actors…"}, {"k": "essentials", "label": "2 — Select the essentials", "ph": "The 4–5 points that really matter…"}, {"k": "context", "label": "3 — Add context", "ph": "Immediate event + broader debate + one civilisation fact…"}, {"k": "tension", "label": "4 — Identify the tension", "ph": "The conflict of values beneath the facts…"}, {"k": "question", "label": "5 — Write the key question", "ph": "One real question (not 'To what extent…')"}, {"k": "outline", "label": "6 — Build the outline", "ph": "I → II → III, a plan that moves…"}, {"k": "examples", "label": "7 — Select examples", "ph": "Precise, explained, tied to the argument…"}, {"k": "intro", "label": "8 — Prepare the introduction", "ph": "Hook → document → context → question → plan…"}, {"k": "conclusion", "label": "9 — Conclusion & opening", "ph": "Answer the question, then open outward…"}], "grid": ["Document comprehension", "Selection of information", "Summary", "Contextualisation", "Key question", "Outline", "Use of examples", "Analysis", "English accuracy", "Range of vocabulary", "Oral delivery", "Time management", "Interaction"]}}, "help": [{"t": "understanding the document", "mod": "m2"}, {"t": "identifying key information", "mod": "m4"}, {"t": "summarising", "mod": "m5"}, {"t": "contextualising", "mod": "m6"}, {"t": "finding the key question", "mod": "m7"}, {"t": "building an outline", "mod": "m8"}, {"t": "finding examples", "mod": "m9"}, {"t": "speaking clearly", "mod": "m13"}, {"t": "answering questions", "mod": "m14"}, {"t": "managing time", "mod": "m1"}]};
